const menuItems = document?.querySelectorAll('.nav__item--more');
const menuItemsArrow = document?.querySelectorAll('.nav__item--more > .nav__link svg');

let isTouchDevice = window.innerWidth <= 960;

window.addEventListener('resize', function() {
    isTouchDevice =  window.innerWidth <= 960
})

menuItems.forEach(item => {
    item.addEventListener('click', function(event) {
        event.stopPropagation();

        const isActive = item.classList.contains('nav__item--active');
        const isDirectLink = !!item.querySelector(':scope > a');
        const isButton = event.target.closest('.nav__button');
        const isLink = event.target.closest('.nav__item:not(.nav__item--more) > a');
        const searchActive = document?.querySelector('.search--active');
        const btnSearch = document?.querySelector('[data-search]');

        if (searchActive) btnSearch.click();

        if (isActive && isDirectLink || isButton || isLink) {
            return;
        }

        if (!isTouchDevice) {
            const offsetleft = item.getBoundingClientRect().left;
            const listWidth = offsetleft + 360 + 40;
            if ( listWidth > window.innerWidth) {
                item.querySelector('& > .nav__list').style.left = (listWidth - window.innerWidth) * -1 + 'px';
            }
        }

        event.preventDefault();

        if (isActive && !isTouchDevice || !item.closest('nav > ul')) {
            item.classList.remove('nav__item--active');
            return;
        }

        if (!item.closest('.nav__item--active')) {
            menuItems.forEach(activeItem => activeItem.classList.remove('nav__item--active'));
        }

        item.closest('.nav__list')
            .querySelectorAll('.nav__item--active')
            .forEach(activeItem => activeItem.classList.remove('nav__item--active'));

        item.classList.toggle('nav__item--active');
    });
});

menuItemsArrow.forEach(icon => {
    icon.addEventListener('click', function(event) {
        event.stopPropagation();
        event.preventDefault();
        this.closest('.nav__item').classList.toggle('nav__item--active');
    });
})

document.addEventListener('click', function (event) {
    const target = event.target;
    if (!target.closest('nav > ul') && !isTouchDevice) {
        document.querySelector('.nav__item--active')?.classList.remove('nav__item--active');
    }
})

function isOutOfRightViewport(el) {
    if (!el) return false;
    const rect = el.getBoundingClientRect();
    return rect.right > window.innerWidth;
}