let interestThumbsSwiper;
let interestSwiperMain;

function initInterestSwiper() {
   const isMobile = window.innerWidth < 621;

   if (isMobile && !interestThumbsSwiper) {
      interestThumbsSwiper = new Swiper('.interest__thumbs', {
         slidesPerView: 3,
         spaceBetween: 4,
         loop: true,
         slideToClickedSlide: true,
         watchSlidesProgress: true,
      });
   }

   interestSwiperMain = new Swiper('.products_new .interest__swiper', {
      slidesPerView: 1,
      spaceBetween: 20,
      loop: true,
      autoplay: {
         delay: 5000,
         disableOnInteraction: false,
      },
      navigation: {
         nextEl: '.swiper-button-next',
         prevEl: '.swiper-button-prev',
      },
      breakpoints: {
         621: {
            slidesPerView: 2,
            spaceBetween: 20,
         },
          961: {
             slidesPerView: 3,
             spaceBetween: 40,
          },
          1441: {
             slidesPerView: 4,
             spaceBetween: 40,
          },
      },
      thumbs: isMobile && interestThumbsSwiper ? { swiper: interestThumbsSwiper } : {},
   });

   if (isMobile && interestThumbsSwiper && document.querySelector('.products_new .interest__swiper')) {

      const updateThumbsByHidingActive = () => {
         const mainRealIndex = interestSwiperMain.realIndex;

         const target = (mainRealIndex + 1) % interestThumbsSwiper.slides.length;

         interestThumbsSwiper.slideToLoop(target);
      };

      interestSwiperMain.on('slideChange', updateThumbsByHidingActive);

      updateThumbsByHidingActive();
   }
}

initInterestSwiper();

window.addEventListener('resize', () => {
   if (!document.querySelector('.products_new .interest__swiper')) return;
   if (interestSwiperMain) interestSwiperMain.destroy(true, true);
   if (interestThumbsSwiper) {
      interestThumbsSwiper.destroy(true, true);
      interestThumbsSwiper = null;
   }
   initInterestSwiper();
});

