const mapSelector = document.querySelector('#map');
const targetMapButton = document.querySelectorAll('[data-map]');

functionMap();

function functionMap() {
    window.map = null;

    if (!mapSelector) {
        return;
    }

    initMap();

    async function initMap() {
        await ymaps3.ready;

        const { YMap, YMapDefaultSchemeLayer, YMapMarker, YMapLayer, YMapFeatureDataSource } = ymaps3;
        const { YMapClusterer, clusterByGrid } = await ymaps3.import('@yandex/ymaps3-clusterer@0.0.1');

        function getBoundsFromPoints(coords) {
            let minLat = coords[0][0], maxLat = coords[0][0];
            let minLng = coords[0][1], maxLng = coords[0][1];

            coords.forEach(([lat, lng]) => {
                if (lat < minLat) minLat = lat;
                if (lat > maxLat) maxLat = lat;
                if (lng < minLng) minLng = lng;
                if (lng > maxLng) maxLng = lng;
            });

            return [[minLat, minLng], [maxLat, maxLng]];
        }

        const getCoordinates = (dataMap) => {
            return dataMap.split(';').map(coord => {
                const [x, y] = coord.split(',').map(c => parseFloat(c.trim()));
                return [y, x];
            });
        };

        const coordinates = Array.from(targetMapButton).flatMap(item => getCoordinates(item.dataset.map));

        const map = new YMap(mapSelector, { location: { center: coordinates[0] || [55.751574, 37.573856], zoom: 11 } });

        map
            .addChild(new YMapDefaultSchemeLayer())
            .addChild(new YMapFeatureDataSource({ id: 'my-source' }))
            .addChild(new YMapLayer({ source: 'my-source', type: 'markers', zIndex: 1800 }));

        const marker = (feature) => {
            const coords = feature.geometry.coordinates;
            const contentPin = createMarkerElement();

            contentPin.addEventListener('click', async (e) => {
                e.stopPropagation();
                const address = await fetchAddressFromCoords(coords);
                if (address) showAddressPopup(contentPin, address);
            });

            return new ymaps3.YMapMarker(
                { coordinates: coords, source: 'my-source' },
                contentPin
            );
        };


        const cluster = (coordinates, features) => {
            const domElement = circle(features.length);
            domElement.addEventListener('click', () => {
                const coords = features.map(feature => feature.geometry.coordinates);
                const bounds = getBoundsFromPoints(coords);
                const paddedBounds = expandBounds(bounds, 0.1);
                map.setLocation({ bounds: paddedBounds, duration: 1000, checkZoomRange: true });
            });

            return new ymaps3.YMapMarker(
                { coordinates, source: 'my-source' },
                domElement
            );
        };


        function circle(count) {
            const circle = document.createElement('div');
            circle.classList.add('map__circle');
            circle.innerHTML = `<div class="map__circle-content"><span class="map__circle-text">${count}</span></div>`;
            return circle;
        }

        const points = coordinates.map((lnglat, i) => ({
            type: 'Feature',
            id: i,
            geometry: { coordinates: lnglat },
            properties: { name: '' }
        }));

        const clusterer = new YMapClusterer({
            method: clusterByGrid({ gridSize: 100 }),
            features: points,
            marker,
            cluster,
        });

        map.addChild(clusterer);

        targetMapButton.forEach(item => {
            item.addEventListener('click', () => {
                const coords = getCoordinates(item.dataset.map);

                clearMapMarkers();
                addMarkersToMap(coords);

                if (coords.length === 1) {
                    map.setLocation({ center: coords[0], duration: 1000, zoom: 16 });
                } else {
                    const bounds = getBoundsFromPoints(coords);
                    const paddedBounds = expandBounds(bounds, 0.1);
                    map.setLocation({ paddedBounds, duration: 1000, checkZoomRange: true });
                }

                activateMap(true);
            });
        });

        function calculateZoom(bounds) {
            const [minLat, minLng] = bounds[0];
            const [maxLat, maxLng] = bounds[1];

            const latDiff = maxLat - minLat;
            const lngDiff = maxLng - minLng;

            const zoomLevel = Math.max(10, 14 - Math.max(latDiff, lngDiff) * 50);

            return Math.round(zoomLevel);
        }

        function clearMapMarkers() {
            map.children.forEach(child => {
                if (child instanceof YMapMarker || child instanceof YMapClusterer) {
                    map.removeChild(child);
                }
            });
        }

        function addMarkersToMap(coordsArray) {
            const features = coordsArray.map((coord, i) => ({
                type: 'Feature',
                id: `dynamic-${Date.now()}-${i}`,
                geometry: {
                    coordinates: coord
                },
                properties: {}
            }));

            const dynamicClusterer = new YMapClusterer({
                method: clusterByGrid({ gridSize: 100 }),
                features: features,
                marker,
                cluster: (coords, features) => {
                    const clusterMarker = new ymaps3.YMapMarker({ coordinates: coords, source: 'my-source' }, circle(features.length));

                    clusterMarker.content.addEventListener('click', () => {
                        const clusterCoords = features.map(f => f.geometry.coordinates);
                        const bounds = getBoundsFromPoints(clusterCoords);
                        map.setLocation({ bounds: bounds, duration: 1000 });
                    });

                    return clusterMarker;
                }
            });

            map.addChild(dynamicClusterer);
        }

        function createMarkerElement() {
            const contentPin = document.createElement('div');
            contentPin.classList.add('map__marker');
            contentPin.innerHTML = '<img width="17" height="22.5" src="/upload/demo/img/favicon-light.png" alt="icon" />';
            return contentPin;
        }

        const overlay = document.querySelector(".map__overlay");
        const mapContainer = document.querySelector('.ymaps3x0--map-container');
        let inactivityTimer;
        let isScrolling = false;

        mapContainer.style.pointerEvents = "none";

        overlay.addEventListener("click", () => {
            activateMap();
        });

        function activateMap(focusMap = false) {
            overlay.style.display = "none";
            mapContainer.style.pointerEvents = "auto";
            resetInactivityTimer();
            if (focusMap) return;
            document.addEventListener("scroll", disableMapInteraction);
        }

        function disableMapInteraction() {
            overlay.style.display = "flex";
            mapContainer.style.pointerEvents = "none";
            document.removeEventListener("scroll", disableMapInteraction);
        }

        function resetInactivityTimer() {
            clearTimeout(inactivityTimer);
            inactivityTimer = setTimeout(() => {
                disableMapInteraction();
            }, 2500);
        }

        function showAddressPopup(markerEl, addressText) {

            document.querySelectorAll('.map__address').forEach(el => el.remove());
            document.querySelectorAll('.ymaps3x0--marker').forEach(marker => {
                marker.style.zIndex = '';
            });

            const popup = document.createElement('div');
            popup.classList.add('map__address');
            popup.innerText = addressText;

            popup.style.position = 'absolute';
            popup.style.left = markerEl.offsetLeft + 'px';
            popup.style.top = (markerEl.offsetTop - 80) + 'px';

            markerEl.parentElement.appendChild(popup);

            let ymMarker = markerEl.closest('.ymaps3x0--marker');
            if (ymMarker) {
                ymMarker.style.zIndex = '1000';
            }

            setTimeout(() => {
                popup.remove();
                if (ymMarker) {
                    ymMarker.style.zIndex = '';
                }
            }, 5000);
        }

        function expandBounds(bounds, paddingPercent = 0.1, minPad = 0.005) {
            const [min, max] = bounds;

            const latSpan = max[0] - min[0];
            const lngSpan = max[1] - min[1];

            const expandLat = Math.max(latSpan * paddingPercent, minPad);
            const expandLng = Math.max(lngSpan * paddingPercent, minPad);

            const newMin = [min[0] - expandLat, min[1] - expandLng];
            const newMax = [max[0] + expandLat, max[1] + expandLng];

            return [newMin, newMax];
        }

        mapContainer.addEventListener("mousemove", resetInactivityTimer);
        mapContainer.addEventListener("keydown", resetInactivityTimer);
        mapContainer.addEventListener("touchstart", resetInactivityTimer);
        mapContainer.addEventListener("touchmove", resetInactivityTimer);

        overlay.addEventListener("touchstart", (event) => {
            if (!isScrolling) {
                overlay.classList.add('touch');
            }
            isScrolling = true;
        });

        overlay.addEventListener("touchend", (event) => {
            if (isScrolling) {
                overlay.classList.remove('touch');
                isScrolling = false;
            }
        });
    }

    async function fetchAddressFromCoords(coords) {
        const [lat, lon] = coords;
        const apiKey = '28d65e9d-ebf0-48ce-bddf-f05211c9cbff';
        const url = `https://geocode-maps.yandex.ru/1.x/?format=json&apikey=${apiKey}&geocode=${lat},${lon}`;

        try {
            const response = await fetch(url);
            const data = await response.json();
            const address =
                data.response.GeoObjectCollection.featureMember[0]?.GeoObject?.metaDataProperty?.GeocoderMetaData?.text;
            return address || null;
        } catch (e) {
            console.error('Ошибка при получении адреса:', e);
            return null;
        }
    }

}