import GraphModal from "graph-modal";

const productButtonAdd = document.querySelector('#product-button-add')

if (productButtonAdd) {
    const wrapper = document.querySelector(".product__wrapper");
    const parameter = document.querySelectorAll('.parameter-product__input[type="radio"]');
    const cart = JSON.parse(localStorage.getItem("cart")) || [];

    let product = renderProduct();

    parameter.forEach(item => {
        item.addEventListener('click', function() {
            product = renderProduct();
            updateButton();
        })
    })
    productButtonAdd.addEventListener("click", function() {
        if (isProductInCart(cart, product)) {
            return;
        }

        cart.push(product);

        let nextId = 1;
        if (cart.length > 0) {
            nextId = Math.max(...cart.map(item => item.id || 0)) + 1;
        }

        // Добавляем id в новый товар
        product.id = nextId;

        localStorage.setItem("cart", JSON.stringify(cart));

        updateButton()

        renderModal()
        new GraphModal().open('product');
    })

    // Функция извлекает число из строки
    function extractNumber(str) {
        if (str) {
            return parseInt(str.replace(/[^\d]/g, ''), 10);
        }
    }

    // Функция форматирует число в строку с пробелами через каждые три знака
    function formatNumber(num) {
        if (num) {
            return num.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
        }
    }

    // Функция для проверки наличия товара по data-productid в корзине
    function isProductInCart(cart, product) {
        return cart.some(item => item['data-productid'] === product['data-productid']);
    }

    function updateButton() {
        if (isProductInCart(cart, product)) {
            productButtonAdd.querySelector('.button__text').textContent = 'Товар в корзине'
            // productButtonAdd.classList.add('button--grey')
            productButtonAdd.disabled = true
        } else {
            productButtonAdd.querySelector('.button__text').textContent = 'Добавить в корзину'
            // productButtonAdd.classList.remove('button--grey')
            productButtonAdd.disabled = false
        }
    }

    function renderProduct() {
        const dataAttr = {};
        const selectedInputs = {};
        const inputs = document.querySelectorAll('.parameter-product__input:checked');
        inputs.forEach(input => {
            const inputName = input.name;
            selectedInputs[inputName] = input.value
        });
        inputs.forEach(input => {
            Object.keys(input.dataset).forEach(dataKey => {
                dataAttr[`data-${dataKey}`] = input.dataset[dataKey];
            });
        });

        return  {
            link: location.pathname,
            image: wrapper.querySelector(".swiper-list__image").getAttribute('src').trim(),
            title: wrapper.querySelector(".product__title").innerText.trim(),
            quantity: 1,
            price: {
                value: extractNumber(wrapper.querySelector(".value__price").innerText.trim()),
                discount: wrapper.querySelector('.value__discount')?.innerText.trim() || undefined,
                oldValue: extractNumber(wrapper.querySelector(".value__old")?.innerText.trim()) || undefined,
                currency: '₽',
            },
            parameter: selectedInputs,
            ...dataAttr
        };
    }

    function renderModal() {
        const form = document.querySelector('.product-modal__form');
        const wrapper = document.createElement('div');
        wrapper.classList.add('product-modal__wrap');

        form.innerHTML = '';

        let itemHTML = `
        <img width="280" height="320" class="product-modal__image img" src="${product.image}" alt="${product.title}">
          <div class="product-modal__body">
            <h3 class="product-modal__heading">${product.title}</h3>
            <ul class="product-modal__list">
         `
        for (const [key, value] of Object.entries(product.parameter)) {
            itemHTML += `
              <li class="product-modal__item">
                <span class="product-modal__caption">${key}:</span>
                <span class="product-modal__text">${value}</span>
              </li>
           `;
        }
        itemHTML += `
             </ul>
            <output class="product-modal__output" name="Итого:" id="product-price-total">${formatNumber(product.price.value) + ' ' + product.price.currency}</output>
            <div class="product-modal__row">
              <a href="/cart.html" class="product-modal__button button button--big">
                <span class="button__text">Перейти в корзину</span>
                <svg class="button__icon" width="14" height="14">
                  <use xlink:href="./img/sprite.svg#arrow-btn"></use>
                </svg>
              </a>
              <a href="/checkout.html" class="product-modal__button button button--big">
                <span class="button__text">Оформить заказ</span>
                <svg class="button__icon" width="18" height="18">
                  <use xlink:href="./img/sprite.svg#icon-bag"></use>
                </svg>
              </a>
            </div>
          </div>
         `
        wrapper.innerHTML = itemHTML;

        form.appendChild(wrapper);
    }

    updateButton()
}
